Generate a REST API using Node.js and Express that enables a user to create, read, update, and delete items from a given database table.

### Response:
import { Router } from 'express'

const router = Router()

router.get('/items', (req, res) => {
 const items = db.
  select('*')
  .from('items')

 res.json(items)
})

router.get('/items/:id', (req, res) => {
 const item = db.
  select('*')
  .from('items')
  .where('id', req.params.id)

 res.json(item)
})

router.post('/items', (req, res) => {
 const itemData = req.body

 const createdItem = db('items')
  .insert(itemData)
  .returning('*')

 res.json(createdItem)
})

router.patch('/items/:id', (req, res) => {
 const itemData = req.body
 const updatedItem = db('items')
  .where('id', req.params.id)
  .update(itemData)
   .returning('*')

 res.json(updatedItem)
})

router.delete('/items/:id', (req, res) => {
 const deletedItem = db('items')
  .where('id', req.params.id)
  .delete()
  .returning('*')

  res.json(deletedItem)

})

export default router

