Develop a program to find the least common multiple of given numbers.

### Response:
// C++ program to find LCM of two given numbers
#include<bits/stdc++.h> 
using namespace std; 

int findLCM(int n1, int n2) 
{ 
	// maximum number between n1 and n2 is stored in max
	int max = (n1 > n2) ? n1 : n2; 

	int i = max; 

	// Always true 
	while(1) 
	{ 
		if( i % n1 == 0 && i % n2 == 0 ) 
		{ 
			return i; 
		} 
		i += max; 
	} 
} 

// Driver program 
int main() 
{ 
	int n1 = 2, n2 = 3; 
	cout<<"LCM of "<<n1<<" and "<<n2<<" is "<<findLCM(n1, n2); 
	return 0; 
}

