def find_outlier(data):
    positive_outlier = False
    negative_outlier = False

    for i in data:
        if i > 0 and i > data[0] * 4:
            positive_outlier = True
        if i < 0 and i < data[0] * -4:
            negative_outlier = True

    if positive_outlier is True:
        return max(data)
    elif negative_outlier is True:
        return min(data)

