int main() 
{
  int curPrime = 2;
  printf("%d ", curPrime); // Print the first prime number
  for (int count = 1; count < 7; ) 
  {
    int isPrime = 1;
    for (int div = 2; div <= curPrime/2; div++) 
    {
      if (curPrime % div == 0) 
      {
        isPrime = 0;
        break;
      }
    }
    if (isPrime == 1) 
    {
      printf("%d ", curPrime);
      count++; // Increment the count
    }
    curPrime++;
  }
  return 0;
}

