fn fibonacci(n: u32) -> u32 {
    if n == 0 {
        return 0;
    } else if n == 1 {
        return 1;
    } else {
        return fibonacci(n-1) + fibonacci(n-2)
    }
}

fn main() {
    let n = 10;
    println!("Fibonacci Sequence for n={}:",n);
    for i in 0..n {
        println!("{}: {}", i, fibonacci(i));
    }
}

