### Instruction:
How would you create a program in C# to print the first 10 Fibonacci numbers?

### Response:
public class Program
{
    public static void Main()
    {
        // create a list to store the Fibonacci numbers
        List<int> fibonacci = new List<int>();

        // first two Fibonacci numbers are 0 and 1
        fibonacci.Add(0);
        fibonacci.Add(1);

        // calculate the next Fibonacci number and add to the list
        for (int i = 2; i < 10; i++)
        {
            int val = fibonacci[i - 1] + fibonacci[i - 2];
            fibonacci.Add(val);
        }

        // print the first 10 Fibonacci numbers
        for(int i = 0; i < 10; i++)
        {
            Console.WriteLine(fibonacci[i]);
        }

        Console.ReadKey();
    }
}

