// Function:
const deepCopy = (obj) => {
 if (obj == null || typeof obj !== 'object') {
  return obj;
 }

 let copy = {};

 for (const key in obj) {
  if (obj.hasOwnProperty(key)) {
   const value = obj[key];
   copy[key] = deepCopy(value);
  }
 }

 return copy;
}

